export type CircuitOutcome = "success" | "failure" | "neutral";

/**
 * Normalize the user provided `circuitBreaker` option. Returns `undefined` when
 * the circuit breaker is disabled (option omitted or falsey).
 */
export function resolveCircuitBreakerOptions(
  input: boolean | CircuitBreakerOptions | undefined
): ResolvedCircuitBreakerOptions | undefined {
  if (!input) {
    return undefined;
  }
  const base = input === true ? {} : input;
  return {
    threshold: base.threshold ?? 5,
    cooldown: base.cooldown ?? 30_000,
    halfOpenMaxRequests: base.halfOpenMaxRequests ?? 1,
    failureStatusCodes: base.failureStatusCodes ?? defaultFailureStatusCodes,
