import { createFetch, $fetch } from "../src/index.ts";
import type { Fetch, FetchOptions } from "../src/types.ts";

// A network-free, fully controllable fetch implementation.
type Handler = (
  input: RequestInfo | URL,
  init: RequestInit | undefined,
  call: number
) => Response | Promise<Response>;

function makeClient(handler: Handler, defaults: FetchOptions = {}) {
  let call = 0;
  const fetchMock = vi.fn(((input, init) => {
    call += 1;
    return handler(input as any, init as any, call);
  }) as Fetch);
  const client = createFetch({ fetch: fetchMock as Fetch, defaults });
  return { client, fetchMock };
}

const res = (status: number, body: BodyInit | null = null, headers?: HeadersInit) =>
  new Response(body, { status, headers });

const ORIGIN = "http://api.test";
const url = (path = "/x") => ORIGIN + path;

