      await expect(client(url(), opts)).rejects.toThrow();
    }
    expect(fetchMock).toHaveBeenCalledTimes(5);

    // Circuit is now open: the next request rejects immediately.
    await expect(client(url(), opts)).rejects.toThrow("Circuit breaker is open");
    expect(fetchMock).toHaveBeenCalledTimes(5);
